const { IMPORT_TYPES } = require('../constants/islands');

/**
 * @typedef {import('../helpers/file-system/islands-manifest').IslandsManifest?} ComponentIslands
 * @typedef {Map<string, {} | ComponentIslands>} IslandsImportNameOfFile
 */

class ImportsCache {
  /** @type {Map<string, IslandsImportNameOfFile> | undefined> } */
  #importsMap;

  constructor() {
    this.#importsMap = new Map();
  }

  clear() {
    this.#importsMap.clear();
  }

  /**
   * @param {{
   * initialPath: string,
   * namedExport: boolean,
   * importName: string,
   * componentPath?: string | null,
   * localNamedExport?: boolean,
   * islands?: {} | null | import('../../helpers/file-system/islands-manifest').IslandsManifest
   * }} importData
   */
  addImport({
    initialPath,
    namedExport,
    importName,
    componentPath = null,
    localNamedExport = null,
    islands = null,
  }) {
    const importNameForCache = namedExport ? importName : IMPORT_TYPES.DEFAULT;

    if (!this.#importsMap.has(initialPath)) {
      this.#importsMap.set(initialPath, new Map());
    }

    this.#importsMap.get(initialPath).set(importNameForCache, islands);

    if (componentPath && initialPath !== componentPath) {
      this.addImport({
        initialPath: componentPath,
        namedExport: localNamedExport,
        importName,
        islands,
      });
    }
  }

  /**
   * @param {{ path: string, importName: string, namedExport: boolean }} importInfo
   */
  getImport({ path, importName, namedExport }) {
    return this.#importsMap
      .get(path)
      ?.get(namedExport ? importName : IMPORT_TYPES.DEFAULT);
  }
}

const importsCache = new ImportsCache();

module.exports = {
  importsCache,
};
